external_knowledge:
- 'navigators' refers to users with the role 'admin';
- 'most recent voyage' refers to the most recent order based on order_id;
- 'value of their most recent voyage' refers to the total amount of the most recent order;
- 'arranging the navigators by the richness of their latest explorations' indicates sorting by the total amount of the most recent order.

sql:
SELECT SUM(total_amount) AS total_order_amount
FROM orders
WHERE customer_id = 10;

SELECT order_id, total_amount
FROM orders
WHERE CAST(total_amount AS FLOAT) > (SELECT AVG(CAST(total_amount AS FLOAT)) FROM orders);

SELECT payment_method, payment_gateway
FROM payments
WHERE payment_id = 1;

SELECT order_id, order_date, total_amount, order_status_id
FROM orders
WHERE customer_id = 10 AND order_status_id = 2;

SELECT orders.order_id, orders.customer_id, orders.total_amount, payments.payment_method, payments.amount
FROM orders
JOIN payments ON orders.payment_id = payments.payment_id;

SELECT o.order_id, os.status_name
FROM orders o
JOIN order_status os ON o.order_status_id = os.order_status_id;

